using System.IO.Compression;
class ZipCreator
{
    void CreateArchive()
    {
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now writes UTF-8 by default (sets
        // the EFS flag). The legacy Java consumer expects Shift-JIS filenames,
        // so we explicitly pass the Shift-JIS encoding to preserve the old behavior.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift-JIS");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

